@import url("im_design_system/v0.1.0/css/common.css");
@import url('im_design_system/imds-iconfont/css/imds-iconfont.min.css');

html {
  font-size: 14px;
  overflow-y: auto;
}

.imds-page-title {
  min-height: 3.572rem;
  padding: 0 1.14rem 0 0;
  border-bottom: 1px solid #d5d5d5;
}

.imds-page-title .subtitle {
  font-size: 0.86rem;
}

.imds-page-title .imds-back .button,
.imds-page-title .imds-refresh .button {
  width: 3.22rem;
  height: 3.22rem;
  font-size: 1.43rem;
}

.imds-form-area {
  position: relative;
  border-radius: 4px;
}

@media screen and (max-width: 768px) {
  .imds-form-area > div > div {
    padding-left: 1.5rem !important;
    padding-right: 1.5rem !important;
    margin-top: 1rem !important;
  }
}

/* common */
.im-hichee-container input[type="date"] {
  min-width: 10em;
}

.im-hichee-container input::-webkit-date-and-time-value {
  text-align: left;
}

.im-hichee-container input[type="date"][disabled]::-webkit-calendar-picker-indicator {
  display: none;
}

.im-hichee-container select {
  min-width: 10em;
}

.im-hichee-container select:disabled {
  opacity: 1;
}

/* table layout fixed */
.imds-table-fixed table {
  table-layout: fixed;
}

.imds-table-fixed th {
  vertical-align: middle;
}

.imds-table-fixed th label,
.imds-table-fixed td label {
  max-width: 100%;
  overflow-wrap: break-word;
}

.imds-table-fixed input[type="date"] {
  min-width: 4em;
  max-width: 12em;
}

.imds-table-fixed select {
  min-width: 4em;
}

/* refer field */
.imds-field.imds-pull-down.imds-static-field select:disabled {
  border: 0;
  padding-right: 0;
  padding-left: 0;
  cursor: default;
  background: transparent;
  color: #363636;
}

.imds-field.imds-pull-down.imds-static-field .select::after {
  display: none;
}

.imds-field.imds-checkbox-horizon.imds-static-field .checkbox[disabled] {
  cursor: default;
  color: #363636;
}

.imds-field.imds-textbox.imds-textbox-date.imds-static-field input[type="date"][readonly] {
  cursor: default;
}

.imds-field.imds-textbox.imds-textbox-date.imds-static-field input[type="date"][readonly]::-webkit-calendar-picker-indicator {
  display: none;
}

.field > .control > label.imds-refer-field,
label.imds-refer-field {
  border-bottom: 1px solid #eee;
  margin-bottom: 0.5em;
  min-width: 6em;
  max-width: 100%;
  padding-bottom: calc(0.5em - 1px);
  overflow-wrap: break-word;
  min-height: calc(2.5rem + 1px);
}

.imds-field.imds-static-field .imds-refer-field > .input,
.imds-field.imds-static-field .imds-refer-field select:disabled,
.imds-field.imds-static-field.imds-checkbox-horizon .imds-refer-field {
  border-bottom: 1px solid #eee;
  border-radius: 0;
}

.imds-detail-datetime .field.is-grouped > .control {
  flex-shrink: 1;
  min-width: 0;
}

